//============================================================================
// Module: shift595_driver
// Description: 4片74HC595级联驱动模块，32位串行输出
//              低25位用于25路换能器控制，高7位保留
//
// Hardware Connection:
//   - 4片595级联: 前片Q7'(Pin9) → 下片DS(Pin14)
//   - 共用SHCP(Pin11, srclk) 和 STCP(Pin12, rclk)
//   - OE接地(常开), MR接高(不复位)
//
// Timing:
//   - 50MHz系统时钟分频到10MHz移位时钟(5分频)
//   - 32位移位时间 = 3.2us，远小于40kHz周期25us
//   - MSB first: 最先移出的数据到达第4片595
//
// Author: Auto-generated
// Date:   2024
//============================================================================

module shift595_driver (
    input        clk,       // 50MHz系统时钟
    input        rst_n,     // 低电平复位，异步复位

    // 控制接口
    input        load,      // 触发加载信号（高电平有效，建议在busy=0时发出单个脉冲）
    input [31:0] data,      // 32位并行数据（低25位为25路PWM输出，高7位保留）
    output reg   busy,      // 移位中标志（SHIFT和LATCH阶段为高）

    // 595硬件接口
    output reg   srclk,     // 移位寄存器时钟 SHCP (Pin11)
    output reg   rclk,      // 锁存时钟 STCP (Pin12)
    output reg   ser        // 串行数据输入 DS (Pin14)
);

    //=========================================================================
    // 参数定义
    //=========================================================================
    // 状态机编码
    localparam IDLE  = 2'b00;   // 空闲状态：等待load信号
    localparam SHIFT = 2'b01;   // 移位状态：串行移出32位数据
    localparam LATCH = 2'b10;   // 锁存状态：产生rclk上升沿锁存数据

    // 分频参数：50MHz / 5 = 10MHz
    localparam DIV_CNT_MAX = 3'd4;   // 分频计数器最大值(0~4)
    localparam DIV_HALF    = 3'd2;   // srclk高电平持续计数值(0,1为高，2~4为低)

    // 移位参数
    localparam SHIFT_TOTAL = 6'd32;  // 总移位位数

    // 锁存参数
    localparam LATCH_CYCLES = 2'd2;  // LATCH状态持续的时钟周期数

    //=========================================================================
    // 内部寄存器定义
    //=========================================================================
    reg [1:0]  state;            // 当前状态机状态
    reg [2:0]  clk_div_cnt;      // 时钟分频计数器：0~4，实现5分频
    reg [5:0]  shift_cnt;        // 移位计数器：0~32，记录已完成移位的位数
    reg [31:0] shift_reg;        // 32位移位寄存器，移出时MSB在前
    reg [1:0]  latch_cnt;        // 锁存计数器：在LATCH状态计数

    //=========================================================================
    // 状态机主逻辑 - 时序逻辑（使用非阻塞赋值）
    //=========================================================================
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            //---------------------------------------------------------------
            // 复位初始化：所有信号恢复默认值
            //---------------------------------------------------------------
            state       <= IDLE;        // 回到空闲状态
            busy        <= 1'b0;        // 不忙
            srclk       <= 1'b0;        // 移位时钟默认低电平
            rclk        <= 1'b0;        // 锁存时钟默认低电平
            ser         <= 1'b0;        // 串行数据默认低电平
            clk_div_cnt <= 3'd0;        // 分频计数器清零
            shift_cnt   <= 6'd0;        // 移位计数器清零
            shift_reg   <= 32'd0;       // 移位寄存器清零
            latch_cnt   <= 2'd0;        // 锁存计数器清零
        end else begin
            case (state)

                //=============================================================
                // IDLE 状态：空闲等待
                //=============================================================
                IDLE: begin
                    busy        <= 1'b0;            // 不忙，可接收新数据
                    srclk       <= 1'b0;            // srclk保持低电平
                    rclk        <= 1'b0;            // rclk保持低电平
                    ser         <= 1'b0;            // ser保持低电平
                    clk_div_cnt <= 3'd0;            // 分频计数器清零
                    shift_cnt   <= 6'd0;            // 移位计数器清零
                    latch_cnt   <= 2'd0;            // 锁存计数器清零

                    // 当load有效时，加载数据并进入SHIFT状态
                    if (load) begin
                        state     <= SHIFT;         // 转到移位状态
                        shift_reg <= data;          // 加载32位并行数据到移位寄存器
                        busy      <= 1'b1;          // 置忙标志
                        // 注意：shift_cnt和clk_div_cnt已在上面清零
                    end
                end

                //=============================================================
                // SHIFT 状态：串行移出32位数据
                //=============================================================
                // 时序说明：
                //   - clk_div_cnt循环计数0→1→2→3→4→0，周期5个clk=100ns
                //   - srclk在cnt=0,1时为高电平(40ns)，cnt=2,3,4时为低(60ns)
                //   - srclk上升沿发生在cnt从4→0的时刻，此时数据被打入595
                //   - 在cnt=3的下降沿后更新shift_reg和shift_cnt
                //   - ser始终输出shift_reg[31]（MSB first）
                //
                // 移出顺序：data[31] → data[30] → ... → data[0]
                //          最先移出的data[31]到达最后一片（第4片）595
                //=============================================================
                SHIFT: begin
                    busy <= 1'b1;                   // 移位中，保持忙标志
                    rclk <= 1'b0;                   // rclk保持低电平

                    //-----------------------------------------------------------
                    // 5分频计数器：0~4循环
                    //-----------------------------------------------------------
                    if (clk_div_cnt == DIV_CNT_MAX)
                        clk_div_cnt <= 3'd0;
                    else
                        clk_div_cnt <= clk_div_cnt + 1'b1;

                    //-----------------------------------------------------------
                    // srclk生成：高电平2个周期(cnt=0,1)，低电平3个周期(cnt=2,3,4)
                    // 频率 = 50MHz / 5 = 10MHz，周期100ns
                    // 上升沿在cnt从4→0时产生
                    //-----------------------------------------------------------
                    srclk <= (clk_div_cnt < DIV_HALF) ? 1'b1 : 1'b0;

                    //-----------------------------------------------------------
                    // ser输出：始终输出移位寄存器的最高位（MSB first）
                    // 每完成一位移位，shift_reg左移，下一个bit自动到MSB位置
                    //-----------------------------------------------------------
                    ser <= shift_reg[31];

                    //-----------------------------------------------------------
                    // 在srclk下降沿之后（cnt=3时）更新移位寄存器
                    // 此时srclk已为低，下一个ser数据已稳定，准备下一个周期
                    // shift_reg左移1位，低位补0
                    //-----------------------------------------------------------
                    if (clk_div_cnt == 3'd3) begin
                        shift_reg <= {shift_reg[30:0], 1'b0};  // 左移1位
                        shift_cnt <= shift_cnt + 1'b1;          // 完成位数+1
                    end

                    //-----------------------------------------------------------
                    // 检查32位移位是否全部完成
                    // shift_cnt从0开始计数，当达到32时全部完成
                    // 注意：非阻塞赋值特性，shift_cnt==32在当前周期结束后生效
                    // 因此实际检测比最后一次更新延迟1个时钟周期
                    //-----------------------------------------------------------
                    if (shift_cnt == SHIFT_TOTAL) begin
                        state <= LATCH;             // 进入锁存状态
                    end
                end

                //=============================================================
                // LATCH 状态：产生rclk上升沿锁存数据到输出寄存器
                //=============================================================
                // 时序说明：
                //   - 进入LATCH时rclk立即拉高
                //   - rclk高电平持续LATCH_CYCLES个时钟周期(约40ns)
                //   - 计数达到后rclk拉低，回到IDLE状态
                //   - 595在rclk上升沿将移位寄存器内容锁存到输出寄存器
                //=============================================================
                LATCH: begin
                    busy  <= 1'b1;                  // 锁存期间仍保持忙标志
                    srclk <= 1'b0;                  // srclk保持低电平
                    ser   <= 1'b0;                  // ser保持低电平
                    rclk  <= 1'b1;                  // rclk拉高，产生锁存上升沿

                    // 锁存计数器递增
                    latch_cnt <= latch_cnt + 1'b1;

                    // 达到设定的锁存周期后，回到IDLE
                    // rclk将在回到IDLE时被拉低，完成一个完整的高电平脉冲
                    if (latch_cnt == LATCH_CYCLES) begin
                        state <= IDLE;              // 回到空闲状态
                    end
                end

                //=============================================================
                // 默认状态：安全回到IDLE
                //=============================================================
                default: begin
                    state <= IDLE;
                end
            endcase
        end
    end

    //=========================================================================
    // 时序参数验证（综合时会被优化掉，仅用于仿真检查）
    //=========================================================================
    // 移位时钟频率: 50MHz / 5 = 10MHz
    // 移位时间: 32位 × 100ns = 3.2us
    // 加上锁存时间: ~3.28us
    // 40kHz PWM周期: 25us，刷新一次仅占约13%

endmodule
